import { matchPath } from 'react-router-dom';
import { eventBus } from '../../const';

const EVENT_NAME = Symbol('Cache Tab Update Event');

export type BlockerFunc = () => Promise<boolean>;

export interface TabOptionProps {
    key: string;
    path: string;
    originPath: string;
    app?: string;
    name?: string;
    i18nKey?: string;
    home?: boolean;
    sticky?: boolean;
    closable?: boolean;
    ellipsis?: boolean;
    keepAlive?: boolean; // 用于区分是否是缓存页面，非缓存页面刷新将使用重定向
    time?: number; // Tab创建时间
    width: number; // Tab的宽度
    blockers?: BlockerFunc[];
    onShowFuncs?: (() => void)[];
    onHideFuncs?: (() => void)[];
    onCloseFuncs?: (() => void)[];
}

export interface CachedTabPayload {
    key: string; // Tab的唯一标识, 一般为 pathname
    tab?: TabOptionProps;
    autoRedirect?: boolean;
    force?: boolean;
}

export enum TAB_EVENT_TYPE  {
    CLOSE = 'close',
    CLOSE_OTHER = 'close-other',
    STICKY = 'sticky',
    CANCEL_STICKY = 'cancel-sticky',
    REFRESH = 'refresh',
    UPDATE = 'update',
}

export interface CachedTabEvent {
    type: TAB_EVENT_TYPE;
    data: CachedTabPayload;
}

export const matchRoutePath = (pattern: string | string[], path: string) => {
    return (Array.isArray(pattern) ? pattern : [pattern]).some((p) => {
        return matchPath(p, path);
    });
}

class CachedTab {
    private cache: Map<string, TabOptionProps> = new Map();
    private routes: Map<string, TabOptionProps> = new Map();
    private pathToKeyMap: Map<string, string> = new Map();
    private onShowFuncCache: Map<string, (() => void)[]> = new Map();
    private onHideFuncCache: Map<string, (() => void)[]> = new Map();
    private onCloseFuncCache: Map<string, (() => void)[]> = new Map();
    
    public eventBus = eventBus;

    public emit(data: CachedTabEvent): void {
        eventBus.emit(EVENT_NAME, data);
    }

    public on(callback: (data: any) => void, key: string | symbol = EVENT_NAME): void {
        eventBus.on(key, callback);
    }

    public off(callback: (data: any) => void, key: string | symbol = EVENT_NAME): void {
        eventBus.off(key, callback);
    }

    public get(key: string): TabOptionProps | undefined {
        return this.cache.get(key);
    }

    public set(key: string, tab: TabOptionProps): void {
        this.cache.set(key, tab);
    }

    public setRoutes(routes: TabOptionProps[]): void {
        routes.forEach((route) => {
            const key = route.key || route.path;
            this.routes.set(key, route);
            
            const patterns = Array.isArray(route.path) ? route.path : [route.path];
            patterns.forEach(pattern => {
                this.pathToKeyMap.set(pattern, key);
            });
        })
    }
    
    public addBlocker = (key: string, blocker: BlockerFunc): void => {
        const tab = this.get(key);
        if (tab) {
            if (!tab.blockers) {
                tab.blockers = [];
            }
            tab.blockers.push(blocker);
        }
    }

    public removeBlocker = (key: string, blocker: BlockerFunc): void => {
        const tab = this.get(key);
        if (tab?.blockers) {
            tab.blockers = tab.blockers.filter((b) => b !== blocker);
        }
    }

    public addOnShowFunc = (key: string, func: () => void): void => {
        const cache = this.onShowFuncCache.get(key)

        // 检查func是否已经在缓存中
        if (cache?.includes(func)) {
            return;
        }

        if (cache) {
            cache.push(func);
        } else {
            this.onShowFuncCache.set(key, [func]);
        }
    }

    public addOnHideFunc = (key: string, func: () => void): void => {
        const cache = this.onHideFuncCache.get(key)
        // 检查func是否已经在缓存中
        if (cache?.includes(func)) {
            return;
        }

        if (cache) {
            cache.push(func);
        } else {
            this.onHideFuncCache.set(key, [func]);
        }
    }

    public addOnCloseFunc = (key: string, func: () => void): void => {
        const cache = this.onCloseFuncCache.get(key)

        // 检查func是否已经在缓存中
        if (cache?.includes(func)) {
            return;
        }

        if (cache) {
            cache.push(func);
        } else {
            this.onCloseFuncCache.set(key, [func]);
        }
    }

    public removeOnShowFunc = (key: string, func: () => void): void => {
        const cache = this.onShowFuncCache.get(key);
        if (cache) {
            this.onShowFuncCache.set(key, cache.filter((f) => f !== func));
        }
    }

    public removeOnHideFunc = (key: string, func: () => void): void => {
        const cache = this.onHideFuncCache.get(key);
        if (cache) {
            this.onHideFuncCache.set(key, cache.filter((f) => f !== func));
        }
    }

    public removeOnCloseFunc = (key: string, func: () => void): void => {
        const cache = this.onCloseFuncCache.get(key);
        if (cache) {
            this.onCloseFuncCache.set(key, cache.filter((f) => f !== func));
        }
    }

    /**
     * onShow 事件, 用于 Tab 显示时触发
     * @param key 
     */
    public onTabShow = (key: string): void => {
        const cache = this.onShowFuncCache.get(key);
        if (cache) {
            cache.forEach((func) => func?.());
        }
    }

    public onTabHide = (key: string): void => {
        const cache = this.onHideFuncCache.get(key);
        if (cache) {
            cache.forEach((func) => func?.());
        }
    }

    public delete(key: string): Promise<boolean> {
        const _this = this;
        const tab = this.cache.get(key);
        return new Promise((resolve, reject) => {
            try {
                if (tab?.blockers && tab.blockers.length > 0) {
                    Promise.all(tab.blockers.map((blocker) => blocker())).then((results) => {
                        if (results.every((r) => r)) {
                            _this.cache.delete(key);
                            resolve(true);
                        } else {
                            resolve(false);
                        }
                    });
                } else {
                    resolve(true);
                }
            } catch (error) {
                reject(error);
            }
        })
    }

    public clear(): void {
        this.cache.clear();
    }

    public getAll(): Map<string, TabOptionProps> {
        return this.cache;
    }

    public has(key: string): boolean {
        return this.cache.has(key);
    }

    public getKeyByPath(path: string): string | undefined {
        if (this.pathToKeyMap.has(path)) {
            return this.pathToKeyMap.get(path);
        }

        for (const [pattern, key] of this.pathToKeyMap) {
            if (matchPath(pattern, path)) {
                return key;
            }
        }
        return undefined;
    }

    /**
     * 关闭 Tab
     * @param pathname 待关闭的 Tab 的 pathname, <Location.pathname>
     */
    public async close(key: string, autoRedirect: boolean = false) {
        const deleteTab = this.get(key);
        const isDelete = await this.delete(key);
        if (isDelete) {
            this.emit({
                type: TAB_EVENT_TYPE.CLOSE,
                data: {
                    key,
                    tab: deleteTab,
                    autoRedirect,
                }
            });
        }
    }

    /**
     * 通过 pathname 关闭 Tab
     * @param pathname 
     */
    public closeByPathname(pathname: string, autoRedirect: boolean = false): void {
        const key = this.getKeyByPath(pathname);
        if (key) {
            this.close(key, autoRedirect);
        }
    }

    /**
     * 关闭当前 Tab
     */
    public closeCurrent(autoRedirect: boolean = false): void {
        const pathname = window.location.pathname;
        this.closeByPathname(pathname, autoRedirect);
    }

    public closeOther(key: string): void {
        const tab = this.get(key);
        this.emit({
            type: TAB_EVENT_TYPE.CLOSE_OTHER,
            data: {
                key,
                tab,
            }
        });
    }

    /**
     * 刷新标签页面内容
     * @param pathname 待刷新的 Tab 的 pathname, <Location.pathname>
     */
    public refresh(key: string, force: boolean = false): void {
        const tab = this.get(key);
        this.emit({
            type: TAB_EVENT_TYPE.REFRESH,
            data: {
                key,
                tab,
                force,
            }
        });
    }

    /**
     * 更新标签内容，比如标签名称，标签跳转地址，标签是否可关闭等
     * @param tab 
     */
    public update(key: string, tab: TabOptionProps): void {
        this.emit({ type: TAB_EVENT_TYPE.UPDATE, data: {
            key,
            tab,
        } });
    }

    /**
     * 固定标签页
     * @param pathname 
     */
    public sticky(key: string): void {
        const tab = this.get(key);
        this.emit({
            type: TAB_EVENT_TYPE.STICKY,
            data: {
                key,
                tab,
            }
        });
    }

    public unSticky(key: string): void {
        const tab = this.get(key);
        this.emit({
            type: TAB_EVENT_TYPE.CANCEL_STICKY,
            data: {
                key,
                tab,
            }
        });
    }
}

export const cachedTab = new CachedTab()
export const refisterCachedTab = () => {
    (window as any).TabEvent = cachedTab;
};

export const TabEventClient = ((window as any).TabEvent ?? cachedTab) as CachedTab;
